import { Card, Image, List } from "antd";

import { useAppDispatch, useAppSelector } from "../../store/connect";
import { setPageTypeId, setSelectedPageType } from "../../store/pageBuilder/pageBuilderSlice";
import { LoadingOutlined } from "@ant-design/icons";

interface PageTypeItem {
    itemId: string;
    title: string;
    Image?: string;
}

const PageType = () => {
    const dispatch = useAppDispatch()
    const { pageTypeList, pageTypeId, isLoading } = useAppSelector(state => state.pageBuilderReducer);

    const handleSelectPageType = (id: string, title: string) => {
        dispatch(setPageTypeId(id));
        dispatch(setSelectedPageType({ label: title, value: id }));
    };

    const totalItems = pageTypeList?.length || 0;
    const columnCount = totalItems > 4 ? Math.ceil(totalItems / 3) : totalItems;

    return (
        <List
            style={{
                maxHeight: "70vh",
                overflowY: "auto",
                overflowX: "hidden",
            }}
            loading={{
                spinning: isLoading,
                indicator: <LoadingOutlined style={{ fontSize: 24, color: "#00737321" }} spin />,
                tip: "Loading Page Types..."
            }}
            grid={{ gutter: 16, column: columnCount || 1 }}
            dataSource={pageTypeList}
            renderItem={(item: PageTypeItem) => (
                <List.Item className={item.itemId === pageTypeId ? "selected-template" : "page-template"} >
                    <Card
                        title={item.title}
                        onClick={() => handleSelectPageType(item.itemId, item.title)}
                        hoverable
                    >
                        <Image
                            style={{ height: 195, objectFit: "cover" }}
                            preview={false}
                            src={item.Image || ""}
                            fallback="data:image/png;base64,"
                        />
                    </Card>
                </List.Item>
            )}
        />
    )
}

export default PageType
